import React from "react";
import { View } from "react-native";

const LazyHome = React.lazy(() => import("./main/Home"));

export const Home = () => (
  <React.Suspense fallback={<View style={{ flex: 1 }} />}>
    <LazyHome />
  </React.Suspense>
);

