import React from "react";

export default function OffcanvasOpener() {
  return (
    <button
      className="btn"
      type="button"
      data-bs-toggle="offcanvas"
      data-bs-target="#offcanvas"
      aria-controls="offcanvas"
    >
      <i className="bi-list text-light"></i>
    </button>
  );
}
